$astLevel < org.eclipse.jdt.core.dom.AST.JLS2 && $astLevel > org.eclipse.jdt.core.dom.AST.getJLSLatest()
=> !org.eclipse.jdt.core.dom.AST.getAllVersions().contains($astLevel)
;;

